mapper.select:

select jobid, version, stepid, db, owner, table_name, pagitype, pagitypedetail, exetype, archiveflag, status, preceding, succedding, seq1, seq2, seq3, pipeline, pk_col, where_col, where_key_name, parallelcnt, commitcnt, wherestr, sqlstr, keymap_id, key_name, key_cols, key_refstr, sqltype, to_char(regdate,'yyyy/mm/dd') as regdate, to_char(upddate,'yyyy/mm/dd') as upddate, reguserid, upduserid
  from cotdl.tbl_piisteptable where jobid= #{jobid} and version= #{version, jdbcType=VARCHAR} 
 order by jobid, stepid, seq1, seq2, seq3

select jobid, version, stepid, db, owner, table_name, pagitype, pagitypedetail, exetype, archiveflag, status, preceding, succedding, seq1, seq2, seq3, pipeline, pk_col, where_col, where_key_name, parallelcnt, commitcnt, wherestr, sqlstr, keymap_id, key_name, key_cols, key_refstr, sqltype, to_char(regdate,'yyyy/mm/dd') as regdate, to_char(upddate,'yyyy/mm/dd') as upddate, reguserid, upduserid
  from cotdl.tbl_piisteptable 
 where jobid= #{jobid} and version= #{version, jdbcType=VARCHAR} and stepid= #{stepid} and db= #{db} and owner= #{owner} and table_name= #{table_name}

select jobid, version, stepid, db, owner, table_name, pagitype, pagitypedetail, exetype, archiveflag, status, preceding, succedding, seq1, seq2, seq3, pipeline, pk_col, where_col, where_key_name, parallelcnt, commitcnt, wherestr, sqlstr, keymap_id, key_name, key_cols, key_refstr, sqltype, to_char(regdate,'yyyy/mm/dd') as regdate, to_char(upddate,'yyyy/mm/dd') as upddate, reguserid, upduserid
  from cotdl.tbl_piisteptable 
 where jobid= #{jobid} and version= #{version, jdbcType=VARCHAR} and stepid= #{stepid} 
   and seq1= #{seq1} and seq2= #{seq2} and seq3= #{seq3}

select count(1) 
  from cotdl.tbl_piisteptable 
 where jobid= #{jobid} and version= #{version, jdbcType=VARCHAR} and exetype= #{exetype} 
   and seq1= #{seq1} and seq2= #{seq2} and seq3= #{seq3}

