mapper.select:
 
		 
		select 
			   jobid, version, stepid, db, owner, table_name, pagitype, pagitypedetail, exetype, archiveflag, status, preceding, succedding, seq1, seq2, seq3, pipeline, pk_col, where_col, where_key_name, parallelcnt, commitcnt, wherestr, sqlstr, keymap_id, key_name, key_cols, key_refstr, sqltype, regdate, upddate, reguserid, upduserid
		from ( 
				select  
					 ROWNUM rn, jobid, version, stepid, db, owner, table_name, pagitype, pagitypedetail, exetype, archiveflag, status, preceding, succedding, seq1, seq2, seq3, pipeline, pk_col, where_col, where_key_name, parallelcnt, commitcnt, wherestr, sqlstr, keymap_id, key_name, key_cols, key_refstr, sqltype, regdate, upddate, reguserid, upduserid
				from (
						select jobid, version, stepid, db, owner, table_name, pagitype, pagitypedetail, exetype, archiveflag, status, preceding, succedding, seq1, seq2, seq3, pipeline, pk_col, where_col, where_key_name, parallelcnt, commitcnt, wherestr, sqlstr, keymap_id, key_name, key_cols, key_refstr, sqltype, to_char(regdate,'yyyy/mm/dd') as regdate, to_char(upddate,'yyyy/mm/dd') as upddate, reguserid, upduserid
						  from cotdl.tbl_piisteptable order by jobid, stepid, seq1, seq2, seq3
					 ) a
				where version in (select max(to_number(version)) from cotdl.tbl_piisteptable where jobid = a.jobid and stepid = a.stepid ) and
		
	    
		
						
							and upper(jobid) = upper(#{search1, jdbcType=VARCHAR})
						
						
							and version = #{search2}
						
						
							and stepid = #{search3}
						
						
							and db = #{search4}
						
						
							and owner = #{search5}
						
						
							and table_name like '%'||#{search6}||'%'
						
		
	    
	    
				 ROWNUM <= #{pagenum} * #{amount} 
				order by jobid, stepid, seq1, seq2, seq3
			  ) f
		where rn > (#{pagenum} -1) * #{amount} 
		order by jobid, stepid, seq1, seq2, seq3

 
		 
		select 
			   jobid, version, stepid, db, owner, table_name, pagitype, pagitypedetail, exetype, archiveflag, status, preceding, succedding, seq1, seq2, seq3, pipeline, pk_col, where_col, where_key_name, parallelcnt, commitcnt, wherestr, sqlstr, keymap_id, key_name, key_cols, key_refstr, sqltype, regdate, upddate, reguserid, upduserid
			   ,db_w, owner_w, table_name_w, updates
		from ( 
				select  
					 ROWNUM rn, a.jobid, a.version, a.stepid, a.db, a.owner, a.table_name, a.pagitype, a.pagitypedetail, a.exetype, a.archiveflag, a.status, a.preceding, a.succedding, a.seq1, a.seq2, a.seq3, a.pipeline, a.pk_col, a.where_col, a.where_key_name, a.parallelcnt, a.commitcnt, a.wherestr, a.sqlstr, a.keymap_id, a.key_name, a.key_cols, a.key_refstr, a.sqltype, a.regdate, a.upddate, a.reguserid, a.upduserid
			   		,b.db_w, b.owner_w, b.table_name_w, c.updates
				from (
						select jobid, version, stepid, db, owner, table_name, pagitype, pagitypedetail, exetype, archiveflag, status, preceding, succedding, seq1, seq2, seq3, pipeline, pk_col, where_col, where_key_name, parallelcnt, commitcnt, wherestr, sqlstr, keymap_id, key_name, key_cols, key_refstr, sqltype, to_char(regdate,'yyyy/mm/dd') as regdate, to_char(upddate,'yyyy/mm/dd') as upddate, reguserid, upduserid
						  from cotdl.tbl_piisteptable order by jobid, stepid, seq1, seq2, seq3
					 ) a
					left outer join cotdl.tbl_piisteptablewait b
					on (a.jobid= b.jobid and a.version= b.version and a.stepid= b.stepid
				  		and a.db= b.db and a.owner= b.owner and a.table_name= b.table_name
					   )
					left outer join (
						select jobid, version, stepid, seq1, seq2, seq3
				              ,listagg(column_name||'='||update_val, ',') within group (order by column_name) as updates
						  from cotdl.tbl_piisteptableupdate 
				          group by jobid, version, stepid, seq1, seq2, seq3
				          ) c
					on (a.jobid= c.jobid and a.version= c.version and a.stepid= c.stepid
				  		and a.seq1= c.seq1 and a.seq2= c.seq2 and a.seq3= c.seq3
					   )
				where a.version in (select max(to_number(version)) from cotdl.tbl_piisteptable where jobid = a.jobid and stepid = a.stepid )
				  and
		

		
						
							and upper(a.jobid) = upper(#{search1, jdbcType=VARCHAR})
						
						
							and a.version = #{search2}
						
						
							and a.stepid = #{search3}
						
						
							and a.db = #{search4}
						
						
							and a.owner = #{search5}
						
						
							and a.table_name like '%'||#{search6}||'%'
						
		
	    
	    
				 ROWNUM <= #{pagenum} * #{amount} 
				order by a.jobid, a.stepid, a.seq1, a.seq2, a.seq3
			  ) f
		where rn > (#{pagenum} -1) * #{amount} 
		order by jobid, stepid, seq1, seq2, seq3
